float fractNoise (vec2 st, int octaves) {
    st *= 4.;
    float result = noise(st);
    if ( octaves >= 2 )
        result += noise(st*2.)*0.5;
    if ( octaves >= 3 )
        result += noise(st*4.)*0.3;
    if ( octaves >= 4 )
        result += noise(st*8.)*0.2;
    if ( octaves >= 5 )
        result += noise(st*16.)*0.1;
    return result;
}


vec2 l2s( vec2 v, mat4 acLTS ) {
    return (vec4(v,0.,1.)*acLTS).xy;
}

vec3 lightning( vec2 st, vec2 a, vec2 b, float scale, float seed, float width, float limit ) {

    vec2 ab = b - a;
    vec2 n = normalize(ab).yx;
    n.y *= -1.;

    vec2 p = projectAndClamp(st-a, ab)+a;
    float t = distance(p,a)/distance(b,a);
    float f = smoothstep(0.,0.5,0.5-abs(t-0.5));

    st += n*(fractNoise(vec2(t,seed),int(octaves))-1.)* scale * 0.3 * length(ab)*f;

    //float c = sdLine(st,a,b);
    float c = length(st - p);
    float l = smoothstep(clamp(limit,0.,0.5)-0.5, .5, abs(0.5-t));
    float xl = clamp(limit-0.5, 0., 1.);
    l = l * (1. - xl) + xl;
    return vec3(smoothstep(0.006*width*core,0.,c),smoothstep(0.034*width,-0.032,c),smoothstep(0.034*width*glow,0.,c)) * l;
}


void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = acLayerNorm;
    st -= 0.5;
    st.x *= acLayerSize.x/acLayerSize.y;

    vec3 lcolor = vec3(0.);

    float adjseed = mod(258.35 + 42.78*seed,138.971);
    float w = 0.1;
    float slimit = 0.2;

    vec2 a = start / 1000.;
    vec2 b = end / 1000.;

    a.y *= -1.;
    b.y *= -1.;

    int icount = int(count);
    for( int i=0; i<icount; i++ ) {
        w += 0.2;
        slimit += 7.4;
        adjseed = mod(adjseed * sin(adjseed+1.2)+4.3,45.32);
        lcolor += lightning(st,a,b, 1., evolution+adjseed, pow((noise(vec2(w,evolution))+1.)/2.,1.584), pow((noise(vec2(slimit,evolution))*limit+1.)/2.584,1.584)) * intensity;
    }

    //if( tint.r >= tint.g && tint.g >= tint.b ) {
    //} else if( tint.r >= tint.b && tint.b >= tint.g ) {
    //}

    //vec4 color = vec4(lcolor,max(max(lcolor.r,lcolor.g),lcolor.b));

    vec4 color = ((color1 * lcolor.r) + (color2 * lcolor.g) + (color3 * lcolor.b)) / 3.;  // max(1., lcolor.r + lcolor.g + lcolor.b);

    color *= alpha;

    vec4 result;
    if( blendMode==0 ) {                // normal
        color *= texColor.a;
        result = color + (texColor*(1.0-color.a));
    } else if( blendMode==1 ) {         // multiply
        vec4 c = color + vec4(1.)*(1.-color.a);
        result = vec4((texColor.rgb/texColor.a)*c.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {         // screen
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-color.rgb)),1.0) * texColor.a;
    //} else if( blendMode==3 ) {         // overflow
    //    result = color;
    } else if( blendMode==4 ) {         // punchout
        result = texColor * (1.0-color.a);
    } else if( blendMode==6 ) {         // sourceonly
        result = color;
    } else if( blendMode==5 ) {         // overlay
        vec3 top = color.rgb / color.a;
        vec3 bot = texColor.rgb / texColor.a;
        vec3 t = smoothstep(0.5,0.5,bot);
        vec3 r3 =
                t * (1. - (1.-2.*(bot-0.5)) * (1.-top)) +
                (1.-t) * ((2.*bot) * top);
        vec4 r4 = vec4(r3, 1.0) * color.a * texColor.a;
        result = texColor * (1.-r4.a) + r4;
    }

    gl_FragColor = result;

}
